mapper.select:
SELECT ssg.seller_id, ssg.seller_name, ssd.YEAR, ssd.MONTH, count( ssd.id ) commerceCount, sum( CASE WHEN ssd.settlement_status = '1' THEN 1 ELSE 0 END ) settlementCount, sum( CASE WHEN ssd.settlement_status = '0' THEN 1 ELSE 0 END ) unSettlementCount, sum( ssd.settlement_amount ) settlementAmount, su.seller_counselor_name FROM store_seller_goods ssg RIGHT JOIN store_sell_detail ssd ON ssg.id = ssd.goods_id LEFT JOIN sys_user su ON ssg.seller_id = su.id
and ssg.seller_name like CONCAT('%', #{sellerCommerceModel.sellerName}, '%')
and ssd.settlement_status = #{sellerCommerceModel.settlementStatus}
and su.seller_counselor_name like CONCAT('%', #{sellerCommerceModel.sellerCounselorName}, '%')
and ssd.year >= #{sellerCommerceModel.startYear} and ssd.month >= #{sellerCommerceModel.startMonth}
and ssd.year <= #{sellerCommerceModel.endYear} and ssd.month <= #{sellerCommerceModel.endMonth}
GROUP BY ssg.seller_id, ssg.seller_name, ssd.YEAR, ssd.MONTH
